import{_ as e,S as a,U as i,a3 as r}from"./framework-68c539c4.js";const n={},t=r('<div class="custom-container tip"><p class="custom-container-title">提示</p><p>每日的写作练习，不需要我们在中间使用特别高级的表达，也不需要我们写一篇完整的作文。但是，我们必须在练习中带有自己对于某事物的观点和看法，并且尝试在最后进行润色。这样，我们在真正写作的时候，只要有了好的想法，就能很轻松地写出属于自己的表达。</p><p>通常来说，我们可以选一些符合自己观点的中文句子，进行翻译和润色。</p><p>我选择先从《顾家北写作》中的 100 个翻译句子练习开始，后面慢慢提升难度。</p></div><h2 id="_2022-12-17" tabindex="-1"><a class="header-anchor" href="#_2022-12-17" aria-hidden="true">#</a> 2022-12-17</h2><h3 id="_1-经常做运动会提高人的自信" tabindex="-1"><a class="header-anchor" href="#_1-经常做运动会提高人的自信" aria-hidden="true">#</a> 1. 经常做运动会提高人的自信</h3><p><mark>Regular exercise</mark> can <mark>increase one&#39;s self-confidence</mark>.</p><h3 id="_2-教学质量对学生成绩有很大影响" tabindex="-1"><a class="header-anchor" href="#_2-教学质量对学生成绩有很大影响" aria-hidden="true">#</a> 2. 教学质量对学生成绩有很大影响</h3><p><mark>The quality of teaching</mark> can make a huge difference to students&#39; <mark>academic performance</mark>.</p><details class="custom-container details"><summary>词伙积累</summary><ul><li>regular exercise: 经常运动</li><li>increase one&#39;s self-confidence: 提高一个人的自信</li><li>the quality of teaching: 教学质量</li><li>academic performance: 学术表现，也就是成绩</li></ul></details><h2 id="_2022-12-19" tabindex="-1"><a class="header-anchor" href="#_2022-12-19" aria-hidden="true">#</a> 2022-12-19</h2><h3 id="_3-家长和老师应该努力去减少小孩看电视的时间" tabindex="-1"><a class="header-anchor" href="#_3-家长和老师应该努力去减少小孩看电视的时间" aria-hidden="true">#</a> 3. 家长和老师应该努力去减少小孩看电视的时间</h3><p>Parents and teachers should make an effort to limit children&#39;s <mark>screen time</mark>.</p><h3 id="_4-经济的下滑导致失业率的上升" tabindex="-1"><a class="header-anchor" href="#_4-经济的下滑导致失业率的上升" aria-hidden="true">#</a> 4. 经济的下滑导致失业率的上升</h3><p><mark>The economic slowdown</mark> has led to a climbing <mark>unemployment rate</mark>.</p><details class="custom-container details"><summary>词伙积累</summary><ul><li>screen time: 看电视/玩电脑 一类盯着屏幕的时间</li><li>the economic slowdown: 经济的下滑</li><li>unemployment rate: 失业率</li></ul></details>',13),c=[t];function s(l,d){return a(),i("div",null,c)}const o=e(n,[["render",s],["__file","04-writing.html.vue"]]);export{o as default};
